solutions.javascript:
// Solution
function validateRouteParameters(path) {
  let parameters = path.match(/:[^/]+/g);
  if (parameters) {
    for (let parameter of parameters) {
      let name = parameter.substring(1);
      if (!/^[a-zA-Z0-9_]+$/.test(name)) {
        return false;
      }
    }
  }
  return true;
}
// Corrected the regular expression to handle nested route parameters
function validateRouteParameters(path) {
  let regex = //:[^/]+/g;
  return path.match(regex) !== null;
}
